import{c as e,Q as a,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"AgentFlow: Synthesizing Multi-Agent Harnesses for Vulnerability Discovery","description":"","frontmatter":{"url":"https://arxiv.org/abs/2604.20801","title":"AgentFlow: Synthesizing Multi-Agent Harnesses for Vulnerability Discovery","date":"2026-04-22T00:00:00.000Z","type":"article"},"headers":[],"relativePath":"research/ai-articles/scored/2026-04-22-agentflow-multi-agent-harnesses.md","filePath":"research/ai-articles/scored/2026-04-22-agentflow-multi-agent-harnesses.md","lastUpdated":1779796674000}'),s={name:"research/ai-articles/scored/2026-04-22-agentflow-multi-agent-harnesses.md"};function i(o,t,l,d,h,g){return a(),r("div",null,[...t[0]||(t[0]=[n(`<h1 id="agentflow-synthesizing-multi-agent-harnesses-for-vulnerability-discovery" tabindex="-1">AgentFlow: Synthesizing Multi-Agent Harnesses for Vulnerability Discovery <a class="header-anchor" href="#agentflow-synthesizing-multi-agent-harnesses-for-vulnerability-discovery" aria-label="Permalink to &quot;AgentFlow: Synthesizing Multi-Agent Harnesses for Vulnerability Discovery&quot;">​</a></h1><p><strong>原始來源</strong>：<a href="https://arxiv.org/abs/2604.20801" target="_blank" rel="noreferrer">https://arxiv.org/abs/2604.20801</a><br><strong>作者</strong>：Hanzhi Liu 等 7 位<br><strong>發表日期</strong>：2026-04-22<br><strong>評分日期</strong>：2026-05-05</p><hr><h2 id="繁體中文全文摘要" tabindex="-1">繁體中文全文摘要 <a class="header-anchor" href="#繁體中文全文摘要" aria-label="Permalink to &quot;繁體中文全文摘要&quot;">​</a></h2><h3 id="核心命題" tabindex="-1">核心命題 <a class="header-anchor" href="#核心命題" aria-label="Permalink to &quot;核心命題&quot;">​</a></h3><p>AgentFlow 自動設計多 Agent 配置，用於安全漏洞發現。不需手動建構 Agent harness，而是使用「<strong>型別化圖形 DSL</strong>」來自動合成和迭代改進 harness 架構。</p><h3 id="統一的-harness-形式化表示" tabindex="-1">統一的 Harness 形式化表示 <a class="header-anchor" href="#統一的-harness-形式化表示" aria-label="Permalink to &quot;統一的 Harness 形式化表示&quot;">​</a></h3><p>論文將 harness 形式化為五個互聯組件的型別化圖形：</p><table tabindex="0"><thead><tr><th>符號</th><th>組件</th><th>說明</th></tr></thead><tbody><tr><td>𝒜</td><td>Agent 角色</td><td>每個 Agent 的職責和能力</td></tr><tr><td>𝒢</td><td>通訊拓撲</td><td>Agent 間的連接和資訊流</td></tr><tr><td>Σ</td><td>訊息 schema</td><td>Agent 間傳遞的資料格式</td></tr><tr><td>Φ</td><td>工具分配</td><td>哪個 Agent 有存取哪些工具的權限</td></tr><tr><td>Ψ</td><td>協調協議</td><td>Agent 協調和決策的規則</td></tr></tbody></table><p><strong>型別系統優勢</strong>：在昂貴的 LLM 執行之前，先拒絕結構上無效的候選方案，過濾掉約 <strong>20%</strong> 的提案。</p><h3 id="執行時驅動的診斷-runtime-driven-diagnostics" tabindex="-1">執行時驅動的診斷（Runtime-Driven Diagnostics） <a class="header-anchor" href="#執行時驅動的診斷-runtime-driven-diagnostics" aria-label="Permalink to &quot;執行時驅動的診斷（Runtime-Driven Diagnostics）&quot;">​</a></h3><p>不使用二元 pass/fail 訊號，而是：</p><blockquote><p>「讀取來自目標程式本身的結構化執行環境反饋（測試判決、行級覆蓋率地圖、sanitizer 報告）」</p></blockquote><p>這種精細反饋讓提案者能：</p><ul><li>辨識哪個組件失敗以及原因</li><li>針對性地修復（而非盲目嘗試）</li></ul><p><strong>案例研究</strong>：HEIF 解析器漏洞利用的三次迭代改進：</p><ol><li>格式驗證失敗 → 增加分析器 Agent</li><li>覆蓋率顯示未觸及脆弱分支 → 增加驗證者 Agent</li><li>啟用 AddressSanitizer 反饋的重試機制</li></ol><h3 id="優化循環" tabindex="-1">優化循環 <a class="header-anchor" href="#優化循環" aria-label="Permalink to &quot;優化循環&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Propose（LLM 生成候選 harness 修改）</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>Execute &amp; Observe（在任務上執行，收集執行環境反饋）</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>Score（領域特定函式評估效能）</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>Diagnose（LLM 分析失敗，建議架構修改）</span></span>
<span class="line"><span>  ↓（迭代）</span></span></code></pre></div><h3 id="實證結果" tabindex="-1">實證結果 <a class="header-anchor" href="#實證結果" aria-label="Permalink to &quot;實證結果&quot;">​</a></h3><h4 id="terminalbench-2-benchmark" tabindex="-1">TerminalBench-2 Benchmark <a class="header-anchor" href="#terminalbench-2-benchmark" aria-label="Permalink to &quot;TerminalBench-2 Benchmark&quot;">​</a></h4><ul><li><strong>AgentFlow</strong>：84.3%（使用 Claude Opus 4.6）</li><li><strong>公開排行榜第一名</strong></li></ul><h4 id="google-chrome-漏洞發現" tabindex="-1">Google Chrome 漏洞發現 <a class="header-anchor" href="#google-chrome-漏洞發現" aria-label="Permalink to &quot;Google Chrome 漏洞發現&quot;">​</a></h4><p>使用 Kimi K2.5 模型對 Google Chrome 進行測試：</p><ul><li>發現 <strong>10 個</strong> 前所未知的零日漏洞</li><li>包含 <strong>2 個 Critical 等級</strong>的沙箱逃逸漏洞： <ul><li>CVE-2026-5280</li><li>CVE-2026-6297</li></ul></li></ul><h3 id="消融研究" tabindex="-1">消融研究 <a class="header-anchor" href="#消融研究" aria-label="Permalink to &quot;消融研究&quot;">​</a></h3><table tabindex="0"><thead><tr><th>組件</th><th>禁用後效能下降</th></tr></thead><tbody><tr><td><strong>Prompt 編輯</strong></td><td><strong>-32.5 個百分點</strong>（最大影響）</td></tr><tr><td>結構編輯</td><td>中等影響</td></tr><tr><td>工具編輯</td><td>補充改善</td></tr></tbody></table><h3 id="關鍵發現-harness-設計-模型能力" tabindex="-1">關鍵發現：Harness 設計 &gt; 模型能力 <a class="header-anchor" href="#關鍵發現-harness-設計-模型能力" aria-label="Permalink to &quot;關鍵發現：Harness 設計 &gt; 模型能力&quot;">​</a></h3><p>同樣的 Claude Opus 4.6 模型，在公開 benchmark 上的效能差異達 <strong>4×</strong>，取決於 harness 設計。</p><blockquote><p>「精良設計的 harness 用更少的推理呼叫解決更多任務。」</p></blockquote><h3 id="對-workspace-的啟示" tabindex="-1">對 Workspace 的啟示 <a class="header-anchor" href="#對-workspace-的啟示" aria-label="Permalink to &quot;對 Workspace 的啟示&quot;">​</a></h3><ol><li><strong>型別化圖形 DSL</strong>：cc-workspace 的 sub-agent 協調目前是非正式的；可借鑒 AgentFlow 的角色、拓撲、協議的明確定義來改善 <code>AGENTS.md</code> 或 <code>subagent-strategy.md</code> 的設計</li><li><strong>Runtime-driven diagnostics</strong>：Agent 失敗時，不只看 pass/fail，要看行級覆蓋率等精細信號</li><li><strong>Prompt 編輯是最大槓桿</strong>（-32.5pp 消融效果）：提示詞品質比架構結構更重要</li><li><strong>4× 效能差異</strong>：同一強模型在不同 harness 下差 4 倍，支持投資 harness 工程</li><li><strong>多 Agent 協調的安全含義</strong>：漏洞發現能力提醒我們，同樣的能力也可用於防禦（red team 測試自己的系統）</li></ol><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>7/10</td><td>型別化 harness DSL 和 runtime diagnostics 概念可改善 sub-agent 協調設計；但目前主要應用在安全領域</td></tr><tr><td>B. 創新性</td><td>9/10</td><td>自動合成多 Agent harness、型別系統過濾、runtime 驅動診斷是重要技術突破</td></tr><tr><td>C. 證據品質</td><td>9/10</td><td>TerminalBench-2 第一名（84.3%），10 個真實 CVE（含 2 個 Critical），消融研究量化各組件貢獻</td></tr><tr><td>D. 技術深度</td><td>8/10</td><td>五組件形式化、型別系統設計、優化循環架構均有具體說明</td></tr><tr><td>E. 泛化性</td><td>7/10</td><td>主要在安全領域驗證；TerminalBench-2 表明可泛化，但跨域遷移未完全驗證</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.95/10</strong></td><td>7×0.3 + 9×0.2 + 9×0.2 + 8×0.15 + 7×0.15 = 2.1+1.8+1.8+1.2+1.05</td></tr></tbody></table><p><strong>整合決策</strong>：Rule<br><strong>整合位置</strong>：<code>.claude/refs/harness-design.md</code>（五組件 harness 形式化 + runtime diagnostics 原則）<br><strong>整合狀態</strong>：待實作</p><p><strong>TODO</strong>：</p><ul><li>在 harness-design.md 加入 AgentFlow 的五組件（𝒜𝒢ΣΦΨ）作為多 Agent 設計的結構性思考框架</li><li>在 security-review skill 中加入「用精細 runtime 信號（覆蓋率、sanitizer 報告）診斷 Agent 安全邊界」的概念</li></ul>`,38)])])}const u=e(s,[["render",i]]);export{p as __pageData,u as default};
